export default function ProtectedRoute({ children, requiredRole }) {
    const { auth } = usePage().props;
    if (!auth.user || auth.user.role !== requiredRole) {
        window.location.href = '/unauthorized'; // Redirect cepat
        return null;
    }
    return children;
}

